const items = $input.all();
const data = items[0].json.body || items[0].json;

const cnj = data.cnj;
const texto = data.texto_processo;
const genero = data.genero_juiz || 'M';
const valorHonorarios = data.valor_honorarios || null;

if (!cnj || !texto) {
  throw new Error('Campos obrigat\u00f3rios: cnj, texto_processo');
}

const textoTruncado = texto.length > 900000 ? texto.substring(0, 900000) : texto;
const vocativo = genero === 'F' ? 'Merit\u00edssima Ju\u00edza' : 'Merit\u00edssimo Juiz';

return [{
  json: {
    cnj,
    texto_processo: textoTruncado,
    genero_juiz: genero,
    vocativo,
    valor_honorarios: valorHonorarios,
    texto_length: texto.length
  }
}];

