  valorHonorarios = Math.round(valorHonorarios / 100) * 100;

  // M\u00ednimo R$ 2.500, m\u00e1ximo R$ 15.000
  valorHonorarios = Math.max(2500, Math.min(15000, valorHonorarios));
}

// Valor por extenso
function valorExtenso(valor) {
  const milhares = Math.floor(valor / 1000);
  const centenas = valor % 1000;
  const extensoMilhares = {1:'um',2:'dois',3:'tr\u00eas',4:'quatro',5:'cinco',6:'seis',7:'sete',8:'oito',9:'nove',10:'dez',11:'onze',12:'doze',13:'treze',14:'quatorze',15:'quinze'};
  const extensoCentenas = {0:'',100:'cem',200:'duzentos',300:'trezentos',400:'quatrocentos',500:'quinhentos',600:'seiscentos',700:'setecentos',800:'oitocentos',900:'novecentos'};

  let resultado = '';
  if (milhares > 0) {
    resultado = (extensoMilhares[milhares] || milhares) + ' mil';
    if (centenas > 0) resultado += ' e ' + (extensoCentenas[centenas] || centenas);
  } else {
    resultado = extensoCentenas[centenas] || centenas.toString();
  }
  return resultado + ' reais';
}

